class LotteryPRD:
    def __init__(self, base=0.4, scaling=0.1, max=0.95):
        self.base = base
        self.scaling = scaling
        self.max = max
        self.failed = 0

    def get_probability(self):
        return min(self.base + self.failed * self.scaling, self.max)

    def draw(self):
        if random.random() < self.get_probability():
            self.failed = 0
            return True
        else:
            self.failed += 1
            return False
